#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef class_T
#define class_T float
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef ENABLE_HP
typedef short cl_half2[2];
#endif

#ifdef BLOCK_STRIDED
#define GET_INDEX(i) ((i) * blockdim + get_local_id(0))
#else
#define GET_INDEX(i) ((i) * blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE + get_local_id(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE + get_global_id(0) % (ELEMENTS_PER_THREAD * FUSION_DEGREE))
#endif

__attribute__((noinline))
class_T bench_block(class_T* data, class_T f) {
    class_T sum = 0;

    #ifdef BASELINE_IMPL
    class_T t = data[0];
    for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
        t = t * t + f;
    }
    sum += t;
    #else
    class_T t_vec[8];
    class_T f_vec[8];

    for(int k=0; k<8; k++) {
        f_vec[k] = data[k];
        t_vec[k] = data[0]; 
    }

    size_t iter_count = COMPUTE_ITERATIONS / 8;
    for (size_t j = 0; j < iter_count; j++) {
        t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
        t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
        t_vec[2] = t_vec[2] * t_vec[2] + f_vec[2];
        t_vec[3] = t_vec[3] * t_vec[3] + f_vec[3];
        t_vec[4] = t_vec[4] * t_vec[4] + f_vec[4];
        t_vec[5] = t_vec[5] * t_vec[5] + f_vec[5];
        t_vec[6] = t_vec[6] * t_vec[6] + f_vec[6];
        t_vec[7] = t_vec[7] * t_vec[7] + f_vec[7];
    }

    size_t remainder = COMPUTE_ITERATIONS % 8;
    if (remainder > 0) t_vec[0] = t_vec[0] * t_vec[0] + f_vec[0];
    if (remainder > 1) t_vec[1] = t_vec[1] * t_vec[1] + f_vec[1];
    if (remainder > 2) t_vec[2] = t_vec[2] * t_vec[2] + f_vec[2];
    if (remainder > 3) t_vec[3] = t_vec[3] * t_vec[3] + f_vec[3];
    if (remainder > 4) t_vec[4] = t_vec[4] * t_vec[4] + f_vec[4];
    if (remainder > 5) t_vec[5] = t_vec[5] * t_vec[5] + f_vec[5];
    if (remainder > 6) t_vec[6] = t_vec[6] * t_vec[6] + f_vec[6];

    sum = t_vec[0] + t_vec[1] + t_vec[2] + t_vec[3] + t_vec[4] + t_vec[5] + t_vec[6] + t_vec[7];
    #endif

    return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* src) {
    class_T local_sum = 0;

    size_t global_idx = get_global_id(0);
    size_t total_elements = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
        for (size_t epw = 0; epw < ELEMENTS_PER_THREAD; epw++) {
            size_t idx = global_idx * ELEMENTS_PER_THREAD * FUSION_DEGREE + fusion * ELEMENTS_PER_THREAD + epw;

            if (idx < total_elements / (sizeof(class_T) == 2 ? 2 : 1)) { 
                class_T f = seed;
                class_T t = src[idx];

                for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
                    t = t * t + f;
                }
                local_sum += t;
            }
        }
    }

    src[global_idx] = local_sum;
}

__kernel void benchmark_func_vec(class_T seed, __global class_T* src) {
    class_T local_sum = 0;

    size_t base_idx = get_global_id(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t total_elements = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
        for (size_t epw = 0; epw < ELEMENTS_PER_THREAD; epw++) {
            size_t idx = base_idx + fusion * ELEMENTS_PER_THREAD + epw;

            if (idx < total_elements) {
                class_T data_block[8];
                for(int k=0; k<8; k++) {
                    if (idx + k < total_elements) {
                        data_block[k] = src[idx + k];
                    } else {
                        data_block[k] = 0;
                    }
                }

                local_sum += bench_block(data_block, seed);
            }
        }
    }

    src[get_global_id(0)] = local_sum;
}

__kernel void warmup_func(short seed, __global int* src) {
    size_t idx = get_global_id(0);
    src[idx] = seed;
}
